challenges.solution:
function fetchSignal(callback) {
  setTimeout(() => callback(null, { id: 1, strength: 85 }), 10);
}
function fetchLocation(signalId, callback) {
  setTimeout(() => callback(null, "north-7"), 10);
}

let locationFromChain = null;

new Promise((resolve) => {
  fetchSignal((err, signal) => resolve(signal));
})
  .then((signal) => {
    return new Promise((resolve) => {
      fetchLocation(signal.id, (err, loc) => resolve(loc));
    });
  })
  .then((loc) => {
    locationFromChain = loc;
  });
